        return s

    result = list(s)
    count = 0
    first_idx = -1
    last_idx = -1

    for i in range(len(s)):
        if result[i] == char:
            count += 1
            if first_idx == -1:
                first_idx = i
            last_idx = i

    if count == 0:
        return s

