def find_Product(arr, n):
    # Dictionary to store counts of each element
    counts = {}
    # Set to store elements that appear exactly once
    unique_elements = set()

    # Count occurrences of each element
    for num in arr:
        if num in counts:
            counts[num] += 1
        else:
            counts[num] = 1

    # Find elements with count of 1
    for num, count in counts.items():
        if count == 1:
            unique_elements.add(num)

    # Calculate product of non-repeated elements
    product = 1
    for num in unique_elements:
        product *= num

    return product

