def find_Product(arr, target):
    def helper(arr, target):
        product = 1
        count = {}
        for num in arr:
            if num in count:
                count[num] += 1
            else:
                count[num] = 1
            if count[num] == 1:
                product *= num
        return product

    result = helper(arr, target)
    return result if result == target else 0

def find_Product(arr, n):
    # Dictionary to store frequency of each element
    frequency_map = {}
    product = 1

    # Count frequencies and calculate product of non-repeated elements
    for num in arr:
        if num not in frequency_map:
            frequency_map[num] = 0
        frequency_map[num] += 1

    # Calculate product of elements that appear exactly once
    for num, count in frequency_map.items():
        if count == 1:
            product *= num

    return product

