def count_Substring_With_Equal_Ends(s):
    if not s:
        return 0

    n = len(s)
    count = 0

    # For each starting position i
    for i in range(n):
        # For each ending position j >= i
        for j in range(i, n):
            if s[i] == s[j]:
                count += 1

    return count

def count_Substring_With_Equal_Ends(s):
