import heapq

def func(lists, k):
    # Count frequency of each number across all lists
    frequency = {}
    for lst in lists:
        for num in lst:
            frequency[num] = frequency.get(num, 0) + 1

    # Use a min-heap to keep track of top k elements
    # Heap will store tuples of (-frequency, number) to simulate max-heap behavior
    heap = []

    for num, freq in frequency.items():
        if len(heap) < k:
            heapq.heappush(heap, (-freq, num))
        else:
            # If current frequency is greater than the smallest frequency in heap
            if freq > -heap[0][0]:
                heapq.heapreplace(heap, (-freq, num))

    # Extract numbers from heap
    result = [num for _, num in heap]

    # Sort result in descending order of frequency, then by number value for consistency
    # Since we used negative frequency, we sort by negative frequency (descending freq) then number
    result.sort(key=lambda x: (-frequency[x], x), reverse=True)

    return result

