        return None

    max_prime = 2
    temp = n

    # Handle factor 2 separately to allow skipping even numbers later
    while temp % 2 == 0:
        max_prime = 2
        temp //= 2

    # Check for odd factors starting from 3
    i = 3
    while i * i <= temp:
        while temp % i == 0:
            max_prime = i
            temp //= i
        i += 2

    # If temp is still greater than 1, then it is a prime number
    if temp > 1:
        max_prime = temp

    return max_prime

def max_Prime_Factors(n):
    def is_prime(num):
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, int(num ** 0.5) + 1, 2):
            if num % i == 0:
                return False
        return True

    factors = []
    temp = n
    while temp > 1:
        for i in range(2, temp + 1):
            if temp % i == 0 and is_prime(i):
                factors.append(i)
                temp = temp // i
                break
    return max(factors) if factors else None

def max_Prime_Factors(n):
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    def find_largest_prime_factor(num):
        if num <= 1:
            return 0

        largest_prime = 2

        # Handle the factor 2
        while num % 2 == 0:
            largest_prime = 2
            num //= 2

        # Check for odd factors from 3 onwards
        i = 3
        while i * i <= num:
            while num % i == 0:
                largest_prime = i
                num //= i
            i += 2

        # If num > 1 after the loop, then it is a prime number
        if num > 1:
            largest_prime = num

        return largest_prime

    return find_largest_prime_factor(n)

