def find_missing(arr):
    """
    Find the missing number in a sorted array of consecutive integers.
    Assumes the array starts from 1 and contains no duplicates.
    """
    n = len(arr)
    if n == 0:
        return 1

    # Check if the last element is missing
    if arr[-1] != n + 1:
        return n + 1

    # Binary search for the missing number
    left, right = 0, n - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == mid + 1:
            left = mid + 1
        else:
            right = mid - 1

    return left + 1

def find_missing(arr):
    """
    Finds the missing number in a sorted array of consecutive integers.
    Assumes the array starts from 1 and has exactly one missing number.
    """
    expected = 1
    for i, num in enumerate(arr):
        if num != expected:
            return expected
        expected += 1
    return expected + 1

def find_missing_optimized(arr):
    """
