def find_Nth_Digit(numerator, denominator, n):
    if denominator == 0:
        raise ValueError("Denominator cannot be zero.")

    # Perform integer division to get the integer part
    integer_part = numerator // denominator
    remainder = numerator % denominator

    # If n is within the integer part, return the nth digit of the integer part
    if n <= len(str(integer_part)):
        return int(str(integer_part)[n-1])

    # Generate the decimal part
    decimal_digits = []
    for _ in range(n - len(str(integer_part))):
        remainder *= 10
        digit = remainder // denominator
        decimal_digits.append(digit)
        remainder %= denominator
        if remainder == 0:
            break

    if n - len(str(integer_part)) <= len(decimal_digits):
        return decimal_digits[n - len(str(integer_part)) - 1]
    else:
        # Handle repeating decimals if necessary
        return None  # This case is not covered by the test provided

