def rearange_string(s: str) -> str:
    if not s:
        return ""

    counter = Counter(s)
    max_count = max(counter.values())
    total = len(s)

    if max_count > (total + 1) // 2:
        return None

    # Sort characters by frequency (descending) then alphabetically
    sorted_chars = sorted(counter.keys(), key=lambda x: (-counter[x], x))

    result = [''] * total
    # Fill even positions first with most frequent characters
    even_pos = 0
    for char in sorted_chars:
        count = counter[char]
        for i in range(count):
            result[even_pos] = char
            even_pos += 2

    # Fill remaining odd positions
    for i in range(even_pos, total, 2):
        if i < total:
            result[i] = sorted_chars[0]

    return ''.join(result)

