def rearange_string(s: str) -> str:
    if not s:
        return ""

    counter = Counter(s)
    max_count = max(counter.values())
    length = len(s)

    if max_count > (length + 1) // 2:
        return None  # Impossible to rearrange

    # Sort characters by frequency (descending) then alphabetically
    sorted_chars = sorted(counter.keys(), key=lambda x: (-counter[x], x))

    result = []
    # Place most frequent characters at even indices first
    even_indices = [i for i in range(0, length, 2)]
    odd_indices = [i for i in range(1, length, 2)]

    # Fill even positions first
    for char in sorted_chars:
        count = counter[char]
        for _ in range(count):
            if even_indices:
                result.append(char)
                even_indices.pop()
            elif odd_indices:
                result.append(char)
                odd_indices.pop()
            else:
                break

    # Fill remaining positions (should be at most 1 char left if valid)
    remaining = length - len(result)
    if remaining > 0:
        # Find a character that still has count
        for char in sorted_chars:
            if counter[char] > 0:
                result.append(char)
                counter[char] -= 1
                break

    return ''.join(result)

