import math

def compute_Last_Digit(a, b):
    if a > b:
        return 0

    fact_a = math.factorial(a)
    fact_b = math.factorial(b)

    if fact_b == 0:
        return 0

    last_digit = fact_b % fact_a

    return last_digit

