def find_Max_Num(digits, k):
    """
    Find the largest number that can be formed with the given digits,
    using at most k digits.

    Args:
        digits (list): List of integers representing digits.
        k (int): Maximum number of digits to use.

    Returns:
        int: The largest number formed.
    """
    if not digits or k <= 0:
        return 0

    n = len(digits)
    if k >= n:
        digits.sort(reverse=True)
        return int("".join(map(str, digits)))

    result = []
    start = 0

    while len(result) < k and start < n:
        end = min(start + k - len(result), n)
        max_digit = -1
        max_idx = -1

        for i in range(start, end):
            if digits[i] > max_digit:
                max_digit = digits[i]
                max_idx = i

        result.append(max_digit)
        start = max_idx + 1

    return int("".join(map(str, result)))

