def find_Max_Num(digits, k):
    if not digits or k <= 0:
        return ""

    n = len(digits)
    if k >= n:
        return "".join(map(str, sorted(digits, reverse=True)))

    # Convert digits to strings for easier manipulation
    digits = [str(d) for d in digits]

    def get_next_permutation(arr):
        if not arr:
            return None
        i = len(arr) - 2
        while i >= 0 and arr[i] >= arr[i + 1]:
            i -= 1
        if i < 0:
            return None
        j = len(arr) - 1
        while j >= 0 and arr[j] <= arr[i]:
            j -= 1
        arr[i], arr[j] = arr[j], arr[i]
        arr[i + 1:] = reversed(arr[i + 1:])
        return arr

    def remove_smallest_from_end(arr, count):
        for _ in range(count):
            if arr:
                min_idx = 0
                for i in range(1, len(arr)):
                    if arr[i] < arr[min_idx]:
                        min_idx = i
                arr.pop(min_idx)
        return arr

    result = []
    for _ in range(k):
        current = digits[:]
        # Find the longest non-increasing suffix
        i = len(current) - 1
        while i > 0 and current[i - 1] >= current[i]:
            i -= 1

        # If the whole list is non-increasing, we need to remove smallest from end
        if i == 0:
            result.extend(remove_smallest_from_end(current, 1))
            continue

        # Find the pivot
        j = len(current) - 1
        while j >= 0 and current[j] <= current[i]:
            j -= 1

        # Swap pivot with next greater element
        current[i], current[j] = current[j], current[i]

        # Reverse the suffix
        current[i + 1:] = reversed(current[i + 1:])

        result.extend(current)
        break

    return "".join(result)

