class MaxLenSub:
    def __init__(self, max_diff: int):
        self.max_diff = max_diff

    def max_len_sub(self, arr: List[int]) -> int:
        if not arr:
            return 0

        dp = {arr[0]: 1}
        for i in range(1, len(arr)):
            current_val = arr[i]
            max_len = 1
            for prev_val, length in dp.items():
                diff = abs(current_val - prev_val)
                if diff <= self.max_diff:
                    max_len = max(max_len, length + 1)
            dp[current_val] = max_len

        return max(dp.values()) if dp else 0


