    # Start with the Bell triangle
    triangle = [[1]]
    current_row = [1]

    for i in range(1, n + 1):
        next_row = []
        for j in range(i):
            if j == 0:
                next_row.append(current_row[j])
            else:
                next_row.append(triangle[i-1][j-1] + current_row[j])
        next_row.append(next_row[-1] + current_row[-1])
        triangle.append(next_row)
        current_row = next_row

