def count_Squares(width, height):
    count = 0
    for i in range(1, width + 1):
        for j in range(1, height + 1):
            if i <= width and j <= height:
                if width >= i and height >= j:
                    if width >= i and height >= j and width % i == 0 and height % j == 0:
                        count += (width // i) * (height // j)
    return count

# Correct logic for counting squares in a rectangle:
# A square of size k x k can fit in a w x h rectangle if k <= min(w, h).
# The number of k x k squares is (w - k + 1) * (h - k + 1).
def count_Squares(width, height):
    count = 0
    for k in range(1, min(width, height) + 1):
        count += (width - k + 1) * (height - k + 1)
    return count

