        s = str(num)
        n = len(s)

        # Check if current number is palindrome
        if is_palindrome(num):
            return num

        # Try next length
        if is_palindrome(num):
            return num

        # Generate palindromes of length n
        start = int(s[: (n+1)//2])
        for i in range(start, int(s[: (n+1)//2]) + 100):
            s_part = str(i)
            if n % 2 == 0:
                palindrome = int(s_part + s_part[::-1])
            else:
                palindrome = int(s_part + s_part[:-1][::-1])

            if palindrome > num:
                return palindrome

        # Generate palindromes of length n+1
        start_next = 10 ** n
        for i in range(start_next, int(str(start_next + 1)[: (n+2)//2]) + 100):
            s_part = str(i)
            if (n+1) % 2 == 0:
                palindrome = int(s_part + s_part[::-1])
            else:
                palindrome = int(s_part + s_part[:-1][::-1])

            if palindrome > num:
                return palindrome

        return -1

    return next_palindrome(n)

