def count_Hexadecimal(start, end):
    if start > end:
        return 0
    # Count numbers in range [start, end] that are hexadecimal (contain at least one hex digit)
    count = 0
    for num in range(start, end + 1):
        hex_str = format(num, 'x')  # lowercase hex without '0x'
        if any(c in 'abcdefabcdef' for c in hex_str):
            count += 1
    return count

