import heapq

def merge_sorted_list(*lists):
    if not lists:
        return iter([])

    # Create a heap of (value, index_in_list, list_index)
    # This ensures stable sorting when values are equal
    heap = []
    for idx, lst in enumerate(lists):
        for i, value in enumerate(lst):
            heapq.heappush(heap, (value, idx, i))

    def merge_iterator():
        while heap:
            value, list_idx, item_idx = heapq.heappop(heap)
            yield value
            if item_idx + 1 < len(lists[list_idx]):
                next_value = lists[list_idx][item_idx + 1]
                heapq.heappush(heap, (next_value, list_idx, item_idx + 1))

    return merge_iterator()

# Helper to verify the merge
