from typing import Iterable, Iterator, List, Any

def merge_sorted_list(*inputs: Iterable[Any]) -> Iterator[Any]:
    if not inputs:
        return

    heap = []
    for i, input_iter in enumerate(inputs):
        try:
            first_item = next(input_iter)
            heapq.heappush(heap, (first_item, i))
        except StopIteration:
            pass

    while heap:
        item, index = heapq.heappop(heap)
        yield item

        try:
            next_item = next(inputs[index])
            heapq.heappush(heap, (next_item, index))
        except StopIteration:
            pass

