        if arr[mid] == target:
            # Check if it's the unique element
            if mid == 0 or arr[mid - 1] != arr[mid]:
                if mid == len(arr) - 1 or arr[mid + 1] != arr[mid]:
                    return arr[mid]
            # If it's part of a pair, move left
            if mid > 0 and arr[mid - 1] == arr[mid]:
                right = mid - 1
            else:
                left = mid + 1
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

