    Find the element that appears only once in a sorted array.
    The array is guaranteed to have exactly one such element.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # If mid is even, check if the element at mid is the same as mid+1
        # If mid is odd, check if the element at mid is the same as mid-1
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            if arr[mid] == arr[mid - 1]:
                right = mid - 1
            else:
                left = mid + 1

    return arr[left]

