def check_triplet(arr, target1, target2, target3):
    """
    Checks if there exists a triplet in the array such that:
    a + b + c = target1 + target2 + target3

    This is equivalent to checking if there exists a triplet with sum equal to the sum of the three targets.
    """
    target_sum = target1 + target2 + target3

    arr.sort()

    for i in range(len(arr) - 2):
        left = i + 1
        right = len(arr) - 1

        while left < right:
            current_sum = arr[i] + arr[left] + arr[right]

            if current_sum == target_sum:
                return True
            elif current_sum < target_sum:
                left += 1
            else:
                right -= 1

    return False

def check_triplet(arr, target1, target2):
