    for i in range(n):
        if i > 0 and arr[i] == arr[i - 1]:
            continue
        for j in range(i + 1, n):
            if j > i + 1 and arr[j] == arr[j - 1]:
                continue
            for k in range(j + 1, n):
                if k > j + 1 and arr[k] == arr[k - 1]:
                    continue
                if arr[i] + arr[j] + arr[k] == target1 + target2:
                    return True
    return False

def check_triplet(arr, target_sum, min_val, max_val):
    arr.sort()
    n = len(arr)
    for i in range(n):
        if i > 0 and arr[i] == arr[i - 1]:
            continue
        if arr[i] > target_sum:
            break
        if arr[i] + arr[i + 1] + arr[i + 2] > target_sum:
            continue
        if arr[i] + arr[n - 2] + arr[n - 1] < target_sum:
            continue

        left = i + 1
        right = n - 1

        while left < right:
            current_sum = arr[i] + arr[left] + arr[right]

            if current_sum == target_sum:
                if min_val <= arr[i] and arr[i] <= max_val and \
                   min_val <= arr[left] and arr[left] <= max_val and \
                   min_val <= arr[right] and arr[right] <= max_val:
                    return True
                else:
                    return False
            elif current_sum < target_sum:
                left += 1
            else:
                right -= 1
    return False

