def find_length(s: str, k: int) -> int:
    def max_diff_substring_count(s: str, k: int) -> int:
        n = len(s)
        if k > n:
            return 0

        # We need to find a substring of length k that maximizes (count_0 - count_1)
        # This is equivalent to maximizing (count_0 - count_1) over all substrings of length k

        # Calculate the difference for the first window of size k
        current_diff = 0
        for i in range(k):
            if s[i] == '0':
                current_diff += 1
            else:
                current_diff -= 1

        max_diff = current_diff

        # Slide the window
        for i in range(k, n):
            # Add the new character
            if s[i] == '0':
                current_diff += 1
            else:
                current_diff -= 1

            # Remove the old character
            if s[i - k] == '0':
                current_diff -= 1
            else:
                current_diff += 1

            max_diff = max(max_diff, current_diff)

        return max_diff

    return max_diff_substring_count(s, k)

