def magic_square_test(matrix):
    n = len(matrix)
    if n == 0:
        return True

    # Check if all elements are present from 1 to n^2
    elements = []
    for row in matrix:
        elements.extend(row)

    if len(elements) != n * n:
        return False

    if set(elements) != set(range(1, n * n + 1)):
        return False

    # Check rows
    for row in matrix:
        if sum(row) != n * (n + 1) // 2:
            return False

    # Check columns
    for col_idx in range(n):
        col_sum = sum(matrix[row_idx][col_idx] for row_idx in range(n))
        if col_sum != n * (n + 1) // 2:
            return False

    # Check diagonals
    diag1_sum = sum(matrix[i][i] for i in range(n))
    diag2_sum = sum(matrix[i][n - 1 - i] for i in range(n))

    if diag1_sum != n * (n + 1) // 2 or diag2_sum != n * (n + 1) // 2:
        return False

    return True

def is_magic_square(matrix):
    if not matrix or not matrix[0]:
        return False
    n = len(matrix)
    if any(len(row) != n for row in matrix):
        return False

    sum_main = sum(matrix[i][i] for i in range(n))
    sum_anti = sum(matrix[i][n - 1 - i] for i in range(n))
    target_sum = sum_main

    if target_sum != sum_anti:
        return False

    for i in range(n):
        if sum(matrix[i]) != target_sum:
            return False
        if sum(matrix[j][i] for j in range(n)) != target_sum:
            return False

    return True

