    # Base charge
    base_charge = 20.00
    # Tiered pricing
    if kwh <= 100:
        rate = 0.30
    elif kwh <= 200:
        rate = 0.40
    else:
        rate = 0.50

    charge = base_charge + (kwh * rate)
    return round(charge, 2)

