def max_path_sum(triangle, start_row, start_col):
    if not triangle:
        return 0

    rows = len(triangle)
    cols = len(triangle[0])

    # Create a DP table
    dp = [[0] * cols for _ in range(rows)]

    # Initialize the first row
    dp[0][0] = triangle[0][0]

    # Fill the DP table
    for i in range(1, rows):
        for j in range(len(triangle[i])):
            # Possible previous positions
            prev_positions = []
            if i > 0 and j >= 0 and j < len(triangle[i-1]):
                prev_positions.append((i-1, j))
            if i > 0 and j > 0 and j-1 < len(triangle[i-1]):
                prev_positions.append((i-1, j-1))

            # Find the maximum from previous positions
            max_prev = float('-inf')
            for prev_row, prev_col in prev_positions:
                if prev_row >= start_row and prev_col >= start_col:
                    max_prev = max(max_prev, dp[prev_row][prev_col])

            if max_prev == float('-inf'):
                dp[i][j] = triangle[i][j]
            else:
                dp[i][j] = triangle[i][j] + max_prev

    # Find the maximum value in the last row
    max_sum = float('-inf')
    for j in range(len(triangle[-1])):
        if j >= start_col:
            max_sum = max(max_sum, dp[-1][j])

    return max_sum

