    def generate_sequence():
        x, y = 0, 1
        while True:
            yield x
            x, y = y, x + y

    def is_in_sequence(num, gen):
        for i, val in enumerate(gen):
            if val == num:
                return True
            # Optimization: if num is less than x, it's not in sequence
            if num < x:
                return False

    # Generate sequence until we find n or exceed n
    gen = generate_sequence()
    if is_in_sequence(n, gen):
        return True
    return False

