def solution(a, b, n):
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        else:
            gcd, x1, y1 = extended_gcd(b % a, a)
            x = y1 - (b // a) * x1
            y = x1
            return gcd, x, y

    gcd, x0, y0 = extended_gcd(a, b)

    if n % gcd != 0:
        return None

    x = x0 * (n // gcd)
    y = y0 * (n // gcd)

    return f"x = {x}, y = {y}"

