import re

class CharacterAnalyzer:
    def __init__(self):
        self.patterns = {
            'uppercase': r'[A-Z]',
            'lowercase': r'[a-z]',
            'special': r'[^\w\s]',
            'numeric': r'[0-9]'
        }

    def find_character(self, text):
        return [
            list(re.findall(self.patterns['uppercase'], text)),
            list(re.findall(self.patterns['lowercase'], text)),
            list(re.findall(self.patterns['special'], text)),
            list(re.findall(self.patterns['numeric'], text))
        ]

def find_character(text):
    analyzer = CharacterAnalyzer()
    return analyzer.find_character(text)

import re

class RegexCharacterFinder:
    def __init__(self):
        self.upper_pattern = re.compile(r'[A-Z]')
        self.lower_pattern = re.compile(r'[a-z]')
        self.special_pattern = re.compile(r'[^A-Za-z0-9]')
        self.numeric_pattern = re.compile(r'[0-9]')

    def find_character(self, text):
        upper_chars = list(self.upper_pattern.findall(text))
        lower_chars = list(self.lower_pattern.findall(text))
        special_chars = list(self.special_pattern.findall(text))
        numeric_chars = list(self.numeric_pattern.findall(text))
        return (upper_chars, lower_chars, special_chars, numeric_chars)

def find_character(text):
    finder = RegexCharacterFinder()
    return finder.find_character(text)

