def prod_Square(n):
    if n <= 0:
        return False

    i = 1
    while i * i <= n:
        if n % (i * i) == 0:
            remaining = n // (i * i)
            j = 1
            while j * j <= remaining:
                if remaining % (j * j) == 0:
                    return True
                j += 1
        i += 1

    return False

