        return False
    if n == 0:
        return True

    # Factorize n to find prime factors with their exponents
    factors = {}
    d = 2
    temp = n
    while d * d <= temp:
        while temp % d == 0:
            factors[d] = factors.get(d, 0) + 1
            temp //= d
        d += 1
    if temp > 1:
        factors[temp] = factors.get(temp, 0) + 1

    # Check if all exponents are even
    for exponent in factors.values():
        if exponent % 2 != 0:
            return False

    return True

