def find_longest_repeating_subseq(s: str) -> int:
    n = len(s)
    if n == 0:
        return 0

    # dp[i][j] will store the length of the longest repeating subsequence
    # using characters from s[0..i-1] and s[0..j-1]
    # We only care about i < j to avoid comparing the same character at the same position
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(i + 1, n + 1):
            if s[i - 1] == s[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    return dp[n][n]

def find_longest_repeating_subseq(s: str) -> int:
    n = len(s)
    if n == 0:
        return 0

    # dp[i][j] will store the length of the longest repeating subsequence
    # considering prefix s[:i+1] and s[:j+1] with i < j
    # We use a 2D array. To save space, we could optimize, but n is likely small for this problem.
    dp = [[0] * n for _ in range(n)]

    max_len = 0

    for i in range(n):
        for j in range(i + 1, n):
            if s[i] == s[j]:
                if i == 0:
                    # If both are at index 0 (effectively same character start), 
                    # the length is 1 if we consider them as the first occurrence.
                    # But we need to ensure they are not at the same position.
                    # Since i < j and i=0, j>0, this is valid.
                    dp[i][j] = 1
                else:
                    dp[i][j] = 1 + dp[i-1][j-1]
                max_len = max(max_len, dp[i][j])
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]) if i > 0 or j > 0 else 0

    return max_len

