def find_longest_repeating_subseq(s: str) -> int:
    """
    Find the length of the longest repeating subsequence such that 
    the two subsequences do not have the same character at the same position.
    """
    n = len(s)
    # dp[i][j] will store the length of the longest repeating subsequence
    # considering s[0..i-1] and s[0..j-1] with i != j.
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(1, n + 1):
            if i == j:
                # Same index, cannot form a valid pair
                dp[i][j] = 0
            elif s[i - 1] == s[j - 1]:
                dp[i][j] = 1 + dp[i - 1][j - 1]
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    return dp[n][n]

