class MinHeap:
    def __init__(self, data=None):
        self.heap = list(data) if data else []
        self._heapify()

    def _heapify(self):
        n = len(self.heap)
        for i in range(n // 2 - 1, -1, -1):
            self._sift_down(i)

    def _sift_down(self, index):
        length = len(self.heap)
        root = index
        while True:
            left = 2 * root + 1
            right = 2 * root + 2
            smallest = root

            if left < length and self.heap[left] < self.heap[smallest]:
                smallest = left
            if right < length and self.heap[right] < self.heap[smallest]:
                smallest = right

            if smallest != root:
                self.heap[root], self.heap[smallest] = self.heap[smallest], self.heap[root]
                root = smallest
            else:
                break

    def remove_min(self):
        if not self.heap:
            return None
        min_val = self.heap[0]
        self.heap[0] = self.heap.pop()
        if self.heap:
            self._sift_down(0)
        return min_val

    def insert(self, item):
        self.heap.append(item)
        self._sift_up(len(self.heap) - 1)

    def _sift_up(self, index):
        while index > 0:
            parent = (index - 1) // 2
            if self.heap[index] < self.heap[parent]:
                self.heap[index], self.heap[parent] = self.heap[parent], self.heap[index]
                index = parent
            else:
                break

    def __getitem__(self, index):
        return self.heap[index]

    def __len__(self):
        return len(self.heap)

    def __eq__(self, other):
        return self.heap == other

    def __repr__(self):
        return repr(self.heap)


def heap_replace(heap, new_item):
    heap_obj = MinHeap(heap)
    min_val = heap_obj.remove_min()
    heap_obj.insert(new_item)
    return heap_obj.heap

