        if not lst1:
            return True
        if not lst2:
            return False
        if isinstance(lst1[0], list) and isinstance(lst2[0], list):
            # Recursive case: both are lists, check each sublist
            return all(is_subset(subset, superset) for subset, superset in zip(lst1, lst2))
