def check_subset_list(lst, sub_lst):
    def is_subset(sub, main):
        if not sub:
            return True
        if not main:
            return False

        if isinstance(sub[0], list) and isinstance(main[0], list):
            # Both are nested lists
            if len(sub) != len(main):
                return False
            for i in range(len(sub)):
                if not is_subset(sub[i], main[i]):
                    return False
            return True
        else:
            # One or both are flat lists
            # Check if all elements in sub are present in main
            sub_set = set(sub)
            main_set = set(main)
            return sub_set.issubset(main_set)

    if not lst:
        return True
    if not sub_lst:
        return False

    if isinstance(lst[0], list) and isinstance(sub_lst[0], list):
        if len(lst) != len(sub_lst):
            return False
        for i in range(len(lst)):
            if not is_subset(lst[i], sub_lst[i]):
                return False
        return True
    else:
        sub_set = set(sub_lst)
        for item in lst:
            if item not in sub_set:
                return False
        return True

