def check_subset_list(subset_list, super_list):
    """
    Check if subset_list is a subset of super_list.
    A nested list is a subset if every element in subset_list (recursively)
    exists in super_list at the same depth level.
    """
    def is_element_in_list(element, target_list):
        if isinstance(element, list):
            if not isinstance(target_list, list):
                return False
            # Check if the nested list exists as a sub-list in target_list
            for i in range(len(target_list)):
                if element == target_list[i]:
                    return True
            return False
        else:
            # For non-list elements, check if it exists in the list
            return element in target_list

    def is_list_subset(subset, super_list):
        if not isinstance(subset, list) or not isinstance(super_list, list):
            return False

        for element in subset:
            if not is_element_in_list(element, super_list):
                return False
        return True

    return is_list_subset(subset_list, super_list)

