        return arr[mid]

    # If left part is sorted
    if arr[start] < arr[mid]:
        if arr[start] < arr[mid - 1]:
            return arr[start]
        return find_Min(arr, start, mid - 1)

    # If right part is sorted
    if arr[mid] < arr[end]:
        return find_Min(arr, mid + 1, end)

    # Middle part is the pivot point
    return find_Min(arr, mid + 1, end)

