from collections import defaultdict

def check_occurences(tuples):
    if not tuples:
        return {}

    # Count occurrences of each tuple
    counts = defaultdict(int)
    for t in tuples:
        counts[t] += 1

    # Find tuples with similar times (same count)
    if not counts:
        return {}

    max_count = max(counts.values())
    min_count = min(counts.values())

    # Group tuples by their count
    count_groups = defaultdict(list)
    for t, c in counts.items():
        count_groups[c].append(t)

    # Return tuples that occur multiple times (count > 1)
    result = {}
    for t, c in counts.items():
        if c > 1:
            result[t] = c

    # If all tuples have the same count, return all of them
    if len(count_groups) == 1:
        for t in counts.keys():
            result[t] = counts[t]

    return result

