    # L is the length of the substring being considered
    for L in range(2, n + 1):
        # i is the starting index
        for i in range(n - L + 1):
            j = i + L - 1  # ending index
            if s[i] == s[j]:
                if L == 2:
                    dp[i][j] = 2
                else:
                    dp[i][j] = 2 + dp[i + 1][j - 1]
            else:
                dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])

    return dp[0][n - 1]

