def is_newman_prime(n):
    """Check if n is a Newman-Shanks-Williams prime."""
    if n <= 1:
        return False
    if n == 2:
        return True

    # Check primality of n
    if n % 2 == 0:
        return False

    sqrt_n = int(math.isqrt(n))
    for i in range(3, sqrt_n + 1, 2):
        if n % i == 0:
            return False

    # Check if n is of the form x^2 + x + 1
    # If n = x^2 + x + 1, then x^2 + x + (1-n) = 0
    # Discriminant D = 1 - 4(1-n) = 4n - 3
    # x = (-1 + sqrt(4n - 3)) / 2
    # For x to be an integer, 4n - 3 must be a perfect square and (-1 + sqrt(4n-3)) must be even

    discriminant = 4 * n - 3
    sqrt_disc = int(math.isqrt(discriminant))

    if sqrt_disc * sqrt_disc != discriminant:
        return False

    if (-1 + sqrt_disc) % 2 != 0:
        return False

    x = (-1 + sqrt_disc) // 2

    # Verify that x^2 + x + 1 = n
    return x * x + x + 1 == n

