class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class LinkedList:
    def __init__(self, elements):
        self.head = None
        if elements:
            current = self.head
            for element in elements:
                new_node = Node(element)
                current.next = new_node
                current = new_node

    def remove_from_end(self, value):
        if not self.head:
            return None

        current = self.head
        previous = None
        found = False

        while current and not found:
            if current.value == value:
                found = True
            else:
                previous = current
                current = current.next

        if not found:
            return None

        if previous is None:
            self.head = current.next
        else:
            previous.next = current.next

        return current

def get_Position(arr, index, value):
    linked_list = LinkedList(arr)
    removed_node = linked_list.remove_from_end(value)

    if removed_node is None:
        return -1

    # Count position from the end based on index
    # index 0 means the element at the end (position 0 from end)
    # index 1 means the element before the last (position 1 from end)

    # Traverse to find the position from the end
    count = 0
    current = linked_list.head
    while current:
        if count == index:
            return count
        current = current.next
        count += 1

    return -1

