def max_sub_array_sum_repeated(arr, k, num_segments):
    """
    Find the largest sum of contiguous subarray in the array formed by repeating arr k times.

    Args:
        arr: List of integers
        k: Number of times to repeat the array
        num_segments: Number of segments to consider (in this case, it's the target number of repetitions)

    Returns:
        Maximum sum of a contiguous subarray
    """
    def max_sub_array_sum(nums):
        """Kadane's algorithm to find max subarray sum"""
        if not nums:
            return 0
        max_so_far = nums[0]
        max_ending_here = nums[0]
        for x in nums[1:]:
            max_ending_here = max(x, max_ending_here + x)
            max_so_far = max(max_so_far, max_ending_here)
        return max_so_far

    def max_subarray_sum_with_repetition(arr, n):
        """Find max subarray sum in array repeated n times"""
        total_sum = sum(arr)

        if total_sum <= 0:
            # If total sum is non-positive, we can't wrap around to get extra points
            return max_sub_array_sum(arr * n)

        # Calculate prefix sums
        prefix = [0]
        for x in arr:
            prefix.append(prefix[-1] + x)

        # Calculate suffix sums
        suffix = [0] * (len(arr) + 1)
        for i in range(len(arr) - 1, -1, -1):
            suffix[i] = suffix[i + 1] + arr[i]

        # Max subarray sum within one or few copies
        max_in_one = max_sub_array_sum(arr * 2)

        # Best we can get from wrapping around
        max_wrap = total_sum * (n - 2) + max(prefix) + max(suffix)

        return max(max_in_one, max_wrap)

    # Handle the specific case where we need to repeat k times
    if num_segments <= 1:
        return max_sub_array_sum(arr * num_segments)

    # For larger repetitions, we can use the formula derived
    # The maximum sum is achieved by taking the entire array multiple times
    # plus the best subarray from the beginning and end

    total_sum = sum(arr)

    if total_sum <= 0:
        return max_sub_array_sum(arr * num_segments)

    # Best subarray in one or two copies
    max_two = max_sub_array_sum(arr * 2)

    # Best wrap-around sum
    max_wrap = total_sum * (num_segments - 2) + max(prefix) + max(suffix)

    return max(max_two, max_wrap)

