    count = 0
    for x in arr:
        if x % mod == 0:
            continue
        # Find modular inverse of x modulo p
        # Using Fermat's Little Theorem: x^(p-2) mod p
        inv = pow(x, mod - 2, p)
        if inv == x % p:
            count += 1
    return count

