def find_Element(arr, rotations, k, n):
    def find_element(arr, rotations, k, n):
        if not arr or not rotations or k < 0:
            return None

        total_rotations = sum(rotations)
        total_rotations %= n

        if total_rotations == 0:
            return arr[k] if 0 <= k < n else None

        rotated_arr = arr[-total_rotations:] + arr[:-total_rotations]

        return rotated_arr[k] if 0 <= k < len(rotated_arr) else None

    return find_element(arr, rotations, k, n)

