def find_Element(arr, rotations, index, count):
    if not arr or rotations is None or index < 0 or index >= len(arr):
        return None

    # Handle multiple rotation operations
    for i in range(count):
        if rotations[i] is None:
            continue
        start, end = rotations[i]
        if start >= len(arr) or end >= len(arr):
            continue

        # Perform rotation: move elements from start to end to the beginning
        # This is equivalent to rotating the subarray [start, end]
        subarray = arr[start:end+1]
        arr[start:end+1] = subarray[-1:] + subarray[:-1]

    return arr[index]

