def colon_tuplex(tuplex, start_index, value):
    """
    Returns a new tuple with the element at start_index replaced by [value].
    If start_index is out of bounds, returns the original tuple unchanged.
    """
    if start_index < 0 or start_index >= len(tuplex):
        return tuplex

    new_list = list(tuplex)
    new_list[start_index] = [value]
    return tuple(new_list)

