from typing import List, Any, Union

class ModifiedEncoder:
    def __init__(self, value: Any):
        self.value = value
        self.count = 1

    def append(self, count: int):
        self.count = count

    def __iter__(self):
        return self

    def __next__(self):
        if self.count == 0:
            raise StopIteration
        result = [self.value, self.count]
        self.count = 0
        return result

    def __repr__(self):
        return f"ModifiedEncoder({self.value}, {self.count})"

def modified_encode(data: List[Any]) -> List[Any]:
    result = []
    if not data:
        return result

    current_value = data[0]
    count = 1

    for i in range(1, len(data)):
        if data[i] == current_value:
            count += 1
        else:
            result.append(ModifiedEncoder(current_value, count))
            current_value = data[i]
            count = 1

    result.append(ModifiedEncoder(current_value, count))

    final_result = []
    for item in result:
        final_result.append(item.value)
        final_result.append(item.count)

    return final_result

def max_volume(s):
    if s <= 0:
        return 0
    # The volume of a cuboid with sides a, b, c is V = a*b*c
    # Given constraint: 2*(a+b+c) = s => a+b+c = s/2
    # To maximize V, we need a, b, c to be as close as possible to s/6
    # Since sides must be integers, we try values around s/6
    target = s // 2  # sum of a+b+c
    best_v = 0

    # Iterate a from 1 to target//3
    for a in range(1, target // 3 + 1):
        for b in range(a, (target - a) // 2 + 1):
            c = target - a - b
            if c < b:
                continue
            v = a * b * c
            if v > best_v:
                best_v = v
    return best_v

def max_volume(s):
    # For a cuboid with sides a, b, c, the sum of sides is 2*(a+b+c).
    # We want to maximize V = a*b*c subject to a + b + c = s/2.
    # The maximum occurs when a = b = c = s/6.
    # However, sides must be positive.
    # If s is even, let sum_half = s // 2.
    # We can try integer partitions of sum_half into 3 parts.

    sum_half = s // 2
    if sum_half < 3:
        return 0

    max_v = 0
    for a in range(1, sum_half - 1):
        for b in range(a, (sum_half - a) // 2 + 1):
            c = sum_half - a - b
            if c < b:
                continue
            if a > 0 and b > 0 and c > 0:
                v = a * b * c
                if v > max_v:
                    max_v = v
    return max_v

