        # Initialize a list to store the minimum squares for each number from 0 to target
        dp = [float('inf')] * (target + 1)
        dp[0] = 0

        # Iterate through all numbers from 1 to target
        for i in range(1, target + 1):
            # Check all perfect squares less than or equal to i
            j = 1
            while j * j <= i:
                dp[i] = min(dp[i], 1 + dp[i - j * j])
