def get_Min_Squares(n):
    """
    Returns the minimum number of perfect square numbers that sum to n.
    Uses dynamic programming to solve the problem.
    """
    dp = [float('inf')] * (n + 1)
    dp[0] = 0

    for i in range(1, n + 1):
        for j in range(1, int(i**0.5) + 1):
            dp[i] = min(dp[i], dp[i - j*j] + 1)

    return dp[n]

def get_Min_Squares_recursive(n):
    """
    Alternative recursive solution with memoization.
    """
    memo = {}

    def helper(num):
        if num in memo:
            return memo[num]
        if num == 0:
            return 0
        if num == 1:
            return 1

        min_squares = float('inf')
        for i in range(1, int(num**0.5) + 1):
            min_squares = min(min_squares, 1 + helper(num - i*i))

        memo[num] = min_squares
        return min_squares

    return helper(n)

def get_Min_Squares(n):
    if n == 0:
        return 0
    if n == 1:
        return 1

    dp = [0] * (n + 1)
    dp[0] = 0
    dp[1] = 1

    for i in range(2, n + 1):
        min_val = i // 2 + 1
        for j in range(1, int(i ** 0.5) + 1):
            val = j * j
            if val > i:
                break
            if dp[i - val] + 1 < min_val:
                min_val = dp[i - val] + 1
        dp[i] = min_val

    return dp[n]

def get_Min_Squares(n):
    """
    Find the minimum number of squares whose sum is equal to a given number n.
    This is based on Lagrange's Four-Square Theorem, which states that every natural
    number can be represented as the sum of four integer squares.
    """
    if n == 0:
        return 0

    # Check if n is a perfect square
    if int(n ** 0.5) ** 2 == n:
        return 1

    # Check if n can be represented as sum of two squares
    for i in range(1, int(n ** 0.5) + 1):
        if n - i ** 2 >= 0:
            if is_perfect_square(n - i ** 2):
                return 2

    # Check if n can be represented as sum of three squares
    # Using Legendre's three-square theorem: n = x^2 + y^2 + z^2 if and only if
    # n is not of the form 4^a(8b + 7)
    if is_form_4a_8b_7(n):
        return 4
    else:
        return 3

def is_perfect_square(num):
    """Check if a number is a perfect square."""
    if num < 0:
        return False
    root = int(num ** 0.5)
    return root * root == num

def is_form_4a_8b_7(n):
    """
    Check if n is of the form 4^a(8b + 7).
    If so, it cannot be represented as the sum of three squares.
    """
    a = 0
    while n % 4 == 0:
        n //= 4
        a += 1
    return n % 8 == 7

