    end (int): End of the interval (inclusive)

    Returns:
    int: The maximum occurring divisor
    """
    if start > end:
        return None

    # Dictionary to store the count of each divisor
    divisor_counts = {}

    # Iterate through each number in the interval
    for num in range(start, end + 1):
        # Find all divisors of num
        for i in range(1, int(num**0.5) + 1):
            if num % i == 0:
                if i not in divisor_counts:
                    divisor_counts[i] = 0
                divisor_counts[i] += 1
                if i * i != num:
                    if num // i not in divisor_counts:
                        divisor_counts[num // i] = 0
                    divisor_counts[num // i] += 1

    # Find the maximum occurring divisor
    if not divisor_counts:
        return None

    max_divisor = max(divisor_counts, key=divisor_counts.get)
    return max_divisor

