import heapq

def find_minimum_range(arrays):
    if not arrays:
        return (0, 0)

    # Use a min-heap to track the current minimum element across all arrays
    min_heap = []
    # Track the maximum element among the current pointers in each array
    max_val = 0
    # Track the current index for each array
    pointers = [0] * len(arrays)
    # Store (value, array_index, element_index) in the heap
    for i, arr in enumerate(arrays):
        if arr:
            heapq.heappush(min_heap, (arr[0], i, 0))
            max_val = max(max_val, arr[0])

    smallest_range = (float('inf'), float('inf'))

    while min_heap:
        current_min, array_idx, element_idx = heapq.heappop(min_heap)

        # Calculate the current range
        if max_val - current_min < smallest_range[1] - smallest_range[0]:
            smallest_range = (current_min, max_val)

        # Move the pointer for the array that provided the current minimum
        if element_idx + 1 < len(arrays[array_idx]):
            next_val = arrays[array_idx][element_idx + 1]
            heapq.heappush(min_heap, (next_val, array_idx, element_idx + 1))
            max_val = max(max_val, next_val)
        else:
            # If we've exhausted the array, we can't form a valid range anymore
            break

    return smallest_range

