def count_Squares(width, height):
    count = 0
    # Iterate over all possible top-left corners of squares
    for i in range(width):
        for j in range(height):
            # Check if a square can start at (i, j)
            # The largest square that can fit is limited by the remaining space
            max_side = min(width - i, height - j)
            # Add all possible square sizes that can start at (i, j)
            for size in range(1, max_side + 1):
                count += 1
    return count

def find_ways(n):
