def min_flip_to_make_string_alternate(s: str) -> int:
    """
    Returns the minimum number of flips required to make the binary string
    alternate (either "0101..." or "1010...").
    """
    n = len(s)
    if n == 0:
        return 0

    # Count flips needed to match pattern starting with '0' (0101...)
    flips_starting_with_0 = 0
    for i in range(n):
        expected = '0' if i % 2 == 0 else '1'
        if s[i] != expected:
            flips_starting_with_0 += 1

    # Count flips needed to match pattern starting with '1' (1010...)
    flips_starting_with_1 = 0
    for i in range(n):
        expected = '1' if i % 2 == 0 else '0'
        if s[i] != expected:
            flips_starting_with_1 += 1

    return min(flips_starting_with_0, flips_starting_with_1)

