def smallest_missing(arr, start, end):
    """
    Find the smallest missing element in a sorted array.

    Args:
        arr: List of sorted integers
        start: Starting index (inclusive)
        end: Ending index (inclusive)

    Returns:
        The smallest missing integer in the range [start, end]
    """
    if start > end:
        return arr[start] if start < len(arr) else None

    if arr[end] != end:
        return end

    # Binary search for the first index where arr[i] != i
    left, right = start, end
    while left < right:
        mid = (left + right) // 2
        if arr[mid] == mid:
            left = mid + 1
        else:
            right = mid

    if left > end:
        return end + 1

    return left

