def round_num(number, multiple):
    """
    Rounds the given number to the nearest multiple of 'multiple'.

    Parameters:
        number (int or float): The number to be rounded.
        multiple (int or float): The base multiple to round to.

    Returns:
        int or float: The rounded number.
    """
    if multiple == 0:
        raise ValueError("Multiple cannot be zero.")

    remainder = abs(number % multiple)
    half_multiple = multiple / 2

    if remainder <= half_multiple:
        if number >= 0:
            return (number // multiple) * multiple
        else:
            return ((number // multiple) + 1) * multiple
    else:
        if number >= 0:
            return ((number // multiple) + 1) * multiple
        else:
            return (number // multiple) * multiple

