def get_max_sum(n):
    memo = {}

    def helper(n):
        if n <= 1:
            return n
        if n in memo:
            return memo[n]

        # Calculate the sum of recursive calls with division by 2, 3, 4, 5
        # Ensure integer division
        div_sum = 0
        for div in [2, 3, 4, 5]:
            if n % div == 0:
                div_sum += helper(n // div)
            else:
                div_sum += helper(n // div)  # Floor division

        result = max(div_sum, n)
        memo[n] = result
        return result

    return helper(n)

