def add_nested_tuples(t1, t2):
    """
    Performs index-wise addition of elements in two nested tuples.

    Parameters:
    t1, t2 (tuple): Two nested tuples of equal length and equal inner tuple lengths

    Returns:
    tuple: A tuple containing the sum of corresponding elements at each index

    Raises:
    ValueError: If input tuples have different lengths or inner tuple lengths
    """
    if len(t1) != len(t2):
        raise ValueError("Input tuples must have the same length")

    for i, (inner1, inner2) in enumerate(zip(t1, t2)):
        if len(inner1) != len(inner2):
            raise ValueError(f"Inner tuples at index {i} must have the same length")

    result = []
    for inner1, inner2 in zip(t1, t2):
        result.append(tuple(a + b for a, b in zip(inner1, inner2)))

    return tuple(result)

