def ncr_modp(n, r, p):
    if r < 0 or r > n:
        return 0
    if r == 0 or r == n:
        return 1

    # Compute nCr % p using Lucas' Theorem for prime p
    # Lucas' Theorem: nCr % p = product(ni * ri % p) for i in 0..k
    # where n = n0 + n1*p + ... and r = r0 + r1*p + ...

    def get_digits(num, base):
        digits = []
        while num > 0:
            digits.append(num % base)
            num //= base
        return digits

    n_digits = get_digits(n, p)
    r_digits = get_digits(r, p)

    result = 1
    for ni, ri in zip(n_digits, r_digits):
        if ri > ni:
            return 0
        # Compute niCr % p using Fermat's Little Theorem for modular inverse
        # niCr = ni! / (ri! * (ni-ri)!)
        numerator = factorial_mod(ni, p)
        denominator = (factorial_mod(ri, p) * factorial_mod(ni - ri, p)) % p
        result = (result * numerator * pow(denominator, p - 2, p)) % p

    return result

