def ncr_modp(n, r, p):
    def factorial_mod(n, mod):
        result = 1
        for i in range(2, n + 1):
            result = (result * i) % mod
        return result

    def inverse_mod(a, m):
        m0, x0, x1 = m, 0, 1
        if m == 1:
            return 0
        while a > 1:
            q = a // m
            m, a = a % m, m
            x0, x1 = x1 - q * x0, x0
        if x1 < 0:
            x1 += m0
        return x1

    def combinations_modp(n, r, p):
        if r < 0 or r > n:
            return 0
        if r == 0 or r == n:
            return 1
        if r > n // 2:
            r = n - r

        numerator = factorial_mod(n, p)
        denominator = (factorial_mod(r, p) * factorial_mod(n - r, p)) % p

        return (numerator * inverse_mod(denominator, p)) % p

    return combinations_modp(n, r, p)

