            t = m
            m = a % m
            a = t
            t = y
            y = x - q * y
            x = t
        if x < 0:
            x = x + m0
        return x

    def factorial_mod(n, p):
        result = 1
        for i in range(2, n + 1):
            result = (result * i) % p
        return result

    def factorial(n, p):
