def ncr_modp(n, r, p):
    def factorial_mod(x, mod):
        if x == 0:
            return 1
        return factorial_recursive(x, mod)

    def factorial_recursive(x, mod):
        if x > mod:
            return 0
        res = 1
        for i in range(2, x + 1):
            res = (res * i) % mod
        return res

    # Check if r is valid
    if r < 0 or r > n:
        return 0

    # Calculate n! / (r! * (n-r)!) % p
    # This works for small p where we can precompute factorials, but for general p
    # we need to handle cases where p might be large.
    # However, if p is not prime, division is not straightforward.
    # The problem likely assumes p is prime or expects a specific approach for general p.
    # Given the test case (10, 2, 13), p=13 is prime.
    # If p is not prime, we need to use prime factorization of factorials.

    # Let's implement a general approach using prime factorization of factorials.

    def get_prime_factors(num):
        factors = {}
        d = 2
        temp = num
        while d * d <= temp:
            while temp % d == 0:
                factors[d] = factors.get(d, 0) + 1
                temp //= d
            d += 1
        if temp > 1:
            factors[temp] = factors.get(temp, 0) + 1
        return factors

    def multiply_with_factors(factors, mod):
        result = 1
        for prime, count in factors.items():
            for _ in range(count):
                result = (result * prime) % mod
        return result

    # Factorize n!, r!, and (n-r)!
    def factorial_prime_factors(n):
        factors = {}
        for i in range(2, n + 1):
            factors = get_prime_factors(i)
            for prime, count in factors.items():
                factors[prime] = factors.get(prime, 0) + count
        return factors

    n_fact = factorial_prime_factors(n)
    r_fact = factorial_prime_factors(r)
    nr_fact = factorial_prime_factors(n - r)

    # Subtract exponents for r! and (n-r)!
    res_factors = {}
    for prime, count in n_fact.items():
        res_factors[prime] = res_factors.get(prime, 0) + count - r_fact.get(prime, 0) - nr_fact.get(prime, 0)

    # Compute result modulo p
    return multiply_with_factors(res_factors, p)

